import torch
import torch.nn as nn

class RegularizedModel(nn.Module):
    def __init__(self):
        super().__init__()
        self.layers = nn.Sequential(
            nn.Linear(784, 256),
            nn.ReLU(),
            nn.Dropout(0.3),  # 30% dropout
            nn.Linear(256, 10)
        )

    def forward(self, x):
        return self.layers(x)

# L2 Regularization (Weight Decay) - PyTorch optimizer applies it automatically
optimizer = torch.optim.Adam(model.parameters(), lr=0.001, weight_decay=0.01)

# L1 Regularization - manually add to loss
def l1_loss(output, target, model, lambda_l1=0.01):
    ce_loss = nn.CrossEntropyLoss()(output, target)
    l1_loss = sum(p.abs().sum() for p in model.parameters())
    return ce_loss + lambda_l1 * l1_loss

class EarlyStopping:
    def __init__(self, patience=5, min_delta=0, save_path='checkpoint.pt'):
        self.patience = patience  # epochs to wait after no improvement
        self.min_delta = min_delta  # minimum change to qualify as improvement
        self.counter = 0
        self.best_score = None
        self.early_stop = False
        self.save_path = save_path

    def __call__(self, val_loss, model):
        score = -val_loss  # higher score is better

        if self.best_score is None:
            self.best_score = score
            self.save_checkpoint(model)
        elif score < self.best_score + self.min_delta:
            self.counter += 1
            if self.counter >= self.patience:
                self.early_stop = True
        else:
            self.best_score = score
            self.save_checkpoint(model)
            self.counter = 0

    def save_checkpoint(self, model):
        torch.save(model.state_dict(), self.save_path)

# Usage in training loop
early_stopping = EarlyStopping(patience=10)
for epoch in range(num_epochs):
    train(model, train_loader)
    val_loss = validate(model, val_loader)
    early_stopping(val_loss, model)
    if early_stopping.early_stop:
        print(f"Early stopping at epoch {epoch}")
        break

import numpy as np

def dropout_forward(X, dropout_rate=0.5):
    """Forward pass with dropout"""
    # Generate mask: 1 where kept, 0 where dropped
    mask = np.random.binomial(1, 1 - dropout_rate, X.shape)
    # Apply mask and scale to maintain expected value
    X_dropped = X * mask / (1 - dropout_rate)
    cache = (mask, dropout_rate)
    return X_dropped, cache

def dropout_backward(dout, cache):
    """Backward pass for dropout"""
    mask, dropout_rate = cache
    dx = dout * mask / (1 - dropout_rate)
    return dx

# Inverted dropout (more common implementation)
def inverted_dropout(X, dropout_rate=0.5, training=True):
    """Inverted dropout: scale during training so no scaling needed at test"""
    if training:
        mask = np.random.binomial(1, 1 - dropout_rate, X.shape)
        X = X * mask / (1 - dropout_rate)
        return X, mask
    else:
        return X, None

# Example usage in a simple neural network layer
class DropoutLayer:
    def __init__(self, dropout_rate=0.5):
        self.dropout_rate = dropout_rate
        self.mask = None

    def forward(self, X, training=True):
        if training:
            self.mask = np.random.binomial(1, 1 - self.dropout_rate, X.shape)
            return X * self.mask / (1 - self.dropout_rate)
        return X

    def backward(self, dout):
        return dout * self.mask / (1 - self.dropout_rate)
